function() {
  try {
    var KEY = 'lp_akita_campaign_session_v1';
    var ss = null;
    try {
      ss = window.sessionStorage || null;
    } catch (storageErr) {
      ss = null;
    }

    var query = window.location.search || '';
    var match = /[?&]utm_campaign=([^&#]*)/.exec(query);
    var campaign = match ? decodeURIComponent((match[1] || '').replace(/\+/g, ' ')) : '';
    var isAkita = campaign.toLowerCase().indexOf('akita') !== -1;

    if (isAkita && ss) {
      ss.setItem(KEY, '1');
    }

    return isAkita || !!(ss && ss.getItem(KEY) === '1');
  } catch (e) {
    return false;
  }
}
